from flask import Flask, render_template, request, redirect, url_for, sessionfrom flask_mysqldb import MySQLfrom werkzeug.security import generate_password_hash, check_password_hashprint(generate_password_hash("12345"))app = Flask(__name__)app.secret_key = 'secret123'# =========================# DATABASE CONFIG# =========================app.config['MYSQL_HOST'] = 'localhost'app.config['MYSQL_USER'] = 'root'app.config['MYSQL_PASSWORD'] = ''app.config['MYSQL_DB'] = 'dbtest'mysql = MySQL(app)# =========================# HOME# =========================@app.route('/')def home():    return render_template('home.html')# =========================# LOGIN CLIENT# =========================@app.route('/login', methods=['GET', 'POST'])def login():    if request.method == 'POST':        telephone = request.form['telephone']        password = request.form['password']        cursor = mysql.connection.cursor()        cursor.execute("SELECT * FROM users WHERE telephone=%s AND role='client'", (telephone,))        user = cursor.fetchone()        if user and check_password_hash(user[3], password):            session['user_id'] = user[0]            session['role'] = 'client'            return redirect('/client')        return "Login client incorrect ❌"    return render_template('login.html')# =========================# SIGNUP# =========================@app.route('/signup', methods=['GET', 'POST'])def signup():    if request.method == 'POST':        role = 'client'        # 🚗 chauffeur → login spécial        if role == 'chauffeur':            return redirect('/chauffeur-login')        # 🛠️ admin → login spécial        if role == 'admin':            return redirect('/admin-login')        # 👤 client → inscription normale        nom = request.form['nom']        telephone = request.form.get('telephone')        password = request.form['password']        cursor = mysql.connection.cursor()        cursor.execute("SELECT * FROM users WHERE telephone=%s", (telephone,))        if cursor.fetchone():            return "Email déjà utilisé ❌"        hashed_password = generate_password_hash(password)        cursor.execute(            "INSERT INTO users (nom, telephone, password, role) VALUES (%s, %s, %s, %s)",            (nom, telephone, hashed_password, 'client')        )        mysql.connection.commit()        return redirect('/login')# =========================# LOGIN CHAUFFEUR# =========================@app.route('/chauffeur-login', methods=['GET', 'POST'])def chauffeur_login():    if request.method == 'POST':        id_chauffeur = request.form['id_chauffeur']        password= request.form.get('password')        cursor = mysql.connection.cursor()        cursor.execute(            "SELECT * FROM chauffeur WHERE id_chauffeur=%s",            (id_chauffeur, )        )        chauffeur = cursor.fetchone()        print("DATA:", chauffeur)        print("INPUT PASSWORD:", password)        if chauffeur and check_password_hash(chauffeur[5],password):            session['role'] = 'chauffeur'            session['chauffeur_id'] = chauffeur[0]            return redirect('/driver')        return "ID ou téléphone incorrect ❌"    return render_template('chauffeur_login.html')# =========================# LOGIN ADMIN# =========================@app.route('/admin-login', methods=['GET', 'POST'])def admin_login():    if request.method == 'POST':        admin_id = request.form.get('id')        password = request.form['password']        cursor = mysql.connection.cursor()        cursor.execute("SELECT * FROM users WHERE id=%s AND role='admin'", (admin_id,))        admin = cursor.fetchone()        if admin and  check_password_hash(admin[3], password):            session['role'] = 'admin'            session['admin_id'] = admin[0]            return redirect('/admin')        return "Login admin incorrect ❌"    return render_template('admin_login.html')# =========================# DASHBOARDS# =========================@app.route('/client')def client_dashboard():    if session.get('role') != 'client':        return redirect('/login')    return render_template('client_dashboard.html')@app.route('/driver')def driver_dashboard():    if session.get('role') != 'chauffeur':        return redirect('/chauffeur-login')    return render_template('driver_dashboard.html')@app.route('/admin')def admin_dashboard():    if session.get('role') != 'admin':        return redirect('/admin-login')    return render_template('admin_dashboard.html')# =========================# LOGOUT# =========================@app.route('/logout')def logout():    session.clear()    return redirect('/')#paiement@app.route('/paiement', methods=['GET', 'POST'])def paiement():    prix = request.form.get('prix')    return render_template('client_paiement.html', prix=prix)# =========================# ADD CHAUFFEUR# =========================@app.route('/add_chauffeur', methods=['GET', 'POST'])def add_chauffeur():    if request.method == 'POST':        nom = request.form.get('nom')        prenom = request.form.get('prenom')        telephone = request.form.get('telephone')        id_chauffeur = request.form.get('id_chauffeur')        password = request.form.get('password')        hashed_password = generate_password_hash(password)        cursor = mysql.connection.cursor()        cursor.execute(            "INSERT INTO chauffeur (id_chauffeur,nom, prenom, telephone, password) VALUES (%s, %s, %s, %s, %s)",            (id_chauffeur,nom, prenom, telephone, hashed_password ))        mysql.connection.commit()        cursor.close()        return redirect('/admin')    return render_template('add_chauffeur.html')# =========================# RUN# =========================if __name__ == "__main__":    app.run(debug=True)